 const DENSITY={'서울특별시':'high','부산광역시':'high','대구광역시':'mid','인천광역시':'mid','광주광역시':'mid','대전광역시':'mid','울산광역시':'mid','세종특별자치시':'mid','경기도':'mid','강원특별자치도':'low','충청북도':'low','충청남도':'low','전북특별자치도':'low','전라남도':'low','경상북도':'low','경상남도':'low','제주특별자치도':'mid'};
